INSERT OR REPLACE INTO apps (id, name, description, category, icon, linux_alternative, popularity, homepage, alternative_to) VALUES ('3cx-callflowdesigner', '3CX Call Flow Designer', 'The 3CX Call Flow Designer enables you to easily create voice applications on 3CX communications system. Voice applications are programs that interact with the user via the phone and then perform certain logic. For example, you can create a voice application that asks for a caller to input a customer number, which is then verified against a database. Based on this number the call can then be routed to a certain queue. Because the 3CX Call Flow Designer is entirely visual, little telephony or programming knowledge is required.', 'Development', '3cx-callflowdesigner-icon', 'Linphone / Ekiga / Jami', 0, 'https://www.3cx.com/docs/manual/cfd-installation/', NULL);
INSERT OR REPLACE INTO apps (id, name, description, category, icon, linux_alternative, popularity, homepage, alternative_to) VALUES ('3cx-softphone', '3CXPhone for Windows', 'Looking for a way to make and receive calls from your PC or laptop? Look no further! The 3CX softphone for Windows is a free app developed by 3CX, for use independent of the phone system. Once connected to your VoIP provider, it can be used to make and receive calls over your internet connection.', 'Development', '3cx-softphone-icon', 'Linphone / Jami', 0, 'https://www.3cx.com/', NULL);
