INSERT OR REPLACE INTO apps (id, name, description, category, icon, linux_alternative, popularity, homepage, alternative_to) VALUES ('asdfjkl-jerrychess', 'Jerry - Das Schachprogramm', 'Jerry is a cross-platform chess graphical user interface.
based around one of the world''s best chess program Stockfish
- play against the computer
- adjust strength levels to match your skill
- enter, edit and analyse games
- fully automatic game analysis
- read and save games in standard PGN format
- copy and paste FEN positions and pgn games from clipboard
- cross-platform: modern look on Linux and Windows
- handle large (i.e. 1 GB) PGN files
- easy and intuitive GUI
- free software (GNU GPL 2), no adware/spyware', 'Games', 'asdfjkl-jerrychess-icon', 'Native Linux Version (Java-based) / PyChess / LucasChess (via Wine)', 0, 'https://github.com/asdfjkl/jerry', NULL);
