INSERT OR REPLACE INTO apps (id, name, description, category, icon, linux_alternative, popularity, homepage, alternative_to) VALUES ('binaryfortress-voicebot', 'VoiceBot', 'VoiceBot lets you take command with your voice! Say commands out loud to send actions to your games and applications. Use your voice to type keyboard shortcuts, click and move your mouse, and execute macros and scripts.', 'Games', 'binaryfortress-voicebot-icon', 'OpenASR / Talon / Julius / Whisper', 0, 'https://www.voicebot.net', NULL);
INSERT OR REPLACE INTO apps (id, name, description, category, icon, linux_alternative, popularity, homepage, alternative_to) VALUES ('binaryfortress-windowinspector', 'Window Inspector', 'View the window class, text, properties, and more, simply by moving your mouse cursor over the target window.', 'Utilities', 'binaryfortress-windowinspector-icon', 'xwininfo / xprop / KWin debug tools', 0, 'https://www.binaryfortress.com/WindowInspector/', NULL);
INSERT OR REPLACE INTO apps (id, name, description, category, icon, linux_alternative, popularity, homepage, alternative_to) VALUES ('binarymark-advancedfilefinder', 'Advanced File Finder Free Edition', 'Generate file list of all files with specific name pattern, extension, properties and attributes, as well as text and binary content by recursively scanning specified directories and searching for matching files.
All files can then be saved to file list; copied to a new location specified using either absolute or relative folder paths; or renamed.
Program can use advanced wildcards, RegEx, and case sensitivity options when checking file names.
You can specify file name patterns to exclude from search, as well as directory scanning depth.
When looking for files, program can inspect file contents by looking for specific text or byte pattern.
File search can be further limited by specifing file size, dates, and attribute parameters.
Process 1000s of files using multiple CPU cores in manual, automatic/continuous, triggered/scheduled, or console modes, or directly from Windows Explorer right-click menu.
Save files to output directory specified using either absolute or relative path, with original or new name defined by a mask.
Perform different operations on different files with conditional processing and process branching.
Detailed processing logs are available in both user interface and log files.
Run multiple program instances simultaneously.', 'Utilities', 'binarymark-advancedfilefinder-icon', 'FSearch / Catfish / find / fd', 0, 'https://www.binarymark.com/products/advanced-file-finder', NULL);
INSERT OR REPLACE INTO apps (id, name, description, category, icon, linux_alternative, popularity, homepage, alternative_to) VALUES ('binarymark-batchdocs', 'Batch Docs Free Edition', 'Replace text in, add or remove content, and edit thousands of Word documents in doc and docx formats, PDFs, RTF documents, and other text documents.
- Search and replace in 1000s of text documents
- Use Regular Expressions and RegEx patterns in searches
- Add new text content to hundreds of Word documents
- Remove certain words, phrases, or other text from multiple documents
- Apply new text formatting and styles to specific paragraphs and phrases in word documents in bulk
- Change existing formatting and styles in multiple documents
- Change page layout and size in multiple text documents
- Batch edit document properties like Author, Title, and Subject
- Supports Word documents: docx, doc
- Supports Open Office Documents: odt
- Supports Adobe PDFs
- Supports other text file formats: rtf, txt, wpd, html, xps
- 4 operation modes: Manual, Background, Scheduled, and Console
- Find documents and add them to processing queue depending on their content
- Conditional processing based on document contents, file size, and other attributes
- Rename document files based on file properties document metadata
- Fast parallel processing on multi-core CPUs
- Much more!', 'Design', 'binarymark-batchdocs-icon', 'pandoc / python-docx / LibreOffice CLI', 0, 'https://www.binarymark.com/products/bulk-document-processor?ref=winget', NULL);
INSERT OR REPLACE INTO apps (id, name, description, category, icon, linux_alternative, popularity, homepage, alternative_to) VALUES ('binarymark-batchencodingconverter', 'Batch Encoding Converter Free Edition', 'Convert 1000s of files between more than 100 text encodings and binary formats: Unicode, ANSI, Latin, Cyrillic, ASCII, UTF8, ISO, OEM, Mac, Base-64, Bin-Hex, Quoted-Printable.
Save raw bytes from files as hex, dec, or bin ASCII byte code representations, and convert them back to bytes.
Includes automatic encoding detection, Big Endian, and Unicode support.
Process 1000s of files using multiple CPU cores in manual, automatic, scheduled, console modes, or directly from Windows Explorer right-click menu.
Save files to output directory specified using either absolute or relative path, with original or new name defined by a mask.
Select files for processing based on their name, dates, size, and contents using advanced file search supporting RegEx and advanced wildcards.
Perform different operations on different files with conditional processing and process branching.
Detailed processing logs are available in both user interface and log files.
Run multiple program instances simultaneously.', 'Development', 'binarymark-batchencodingconverter-icon', 'iconv / recode', 0, 'https://www.binarymark.com/products/batch-encoding-converter', NULL);
INSERT OR REPLACE INTO apps (id, name, description, category, icon, linux_alternative, popularity, homepage, alternative_to) VALUES ('binarymark-batchfileencrypt', 'Batch File Encrypt Free Edition', 'Encrypt and decrypt whole files or their parts using AES, Triple-DES (3DES), RC2, and DES symmetric algorithms.
You can encrypt files with a single password or specify cryptographic keys (vectors) instead.
You can change key bit length for better protection.
You can select specifically which bytes in a file should be encrypted/decrypted, though by default the whole file is processed.
Process 1000s of files using multiple CPU cores in manual, automatic/continuous, triggered/scheduled, or console modes, or directly from Windows Explorer right-click menu.
Save files to output directory specified using either absolute or relative path, with original or new name defined by a mask.
Select files for processing based on their name, dates, size, and contents using advanced file search supporting RegEx and advanced wildcards.
Optionally merge together, split all, or zip processed files.
Perform different operations on different files with conditional processing and process branching.
Detailed processing logs are available in both user interface and log files.
Run multiple program instances simultaneously.', 'Design', 'binarymark-batchfileencrypt-icon', 'gpg / Cryptomator / VeraCrypt', 0, 'https://www.binarymark.com/products/batch-file-encrypt', NULL);
INSERT OR REPLACE INTO apps (id, name, description, category, icon, linux_alternative, popularity, homepage, alternative_to) VALUES ('binarymark-batchfilemanager', 'Batch File Manager Free Edition', 'Rename, move, copy, delete, and otherwise manage multiple files.
Rename multiple files according to the rules and pattern you specify using powerful editor with syntax highlighting.
Modify original file name by removing or copying its parts, changing letter case, or adding dynamic content like random characters or file properties.
Copy and move files to folders specified using absolute/relative paths.
Select files for processing based on their name, dates, size, text/binary contents using advanced file search supporting RegEx and advanced wildcards.
Delete files easily.
File operation helpers will guide you step by step through the process.
Process 1000s of files using multiple CPU cores in manual, automatic/continuous, triggered/scheduled, or console modes, or directly from Windows Explorer right-click menu.
Detailed processing logs are available in both user interface and log files.
Run multiple program instances simultaneously.', 'Development', 'binarymark-batchfilemanager-icon', 'Double Commander / Krusader / Bulk Rename (Thunar)', 0, 'https://www.binarymark.com/products/auto-file-manager', NULL);
INSERT OR REPLACE INTO apps (id, name, description, category, icon, linux_alternative, popularity, homepage, alternative_to) VALUES ('binarymark-batchfilerename', 'Batch File Rename Free Edition', 'Rename multiple files according to the rules and pattern you specify using powerful editor with syntax highlighting.
Modify original file name by removing or copying its parts, replacing text, changing letter case, or using Regular Expressions.
Include dynamic elements in file names: file properties (dates, size); hashes (MD5, SHA1, SHA2, CRC); MP3 ID3 and JPG EXIF tags; random characters; current date and time; parent folder name; etc.
Process 1000s of files using multiple CPU cores in manual, automatic/continuous, triggered/scheduled, or console modes, or directly from Windows Explorer right-click menu.
