INSERT OR REPLACE INTO apps (id, name, description, category, icon, linux_alternative, popularity, homepage, alternative_to) VALUES ('bitsum-parkcontrol', 'ParkControl', 'ParkControl is free software to display and tweak CPU core parking settings in real-time. It also has an assortment of complimentary power automation features.', 'Utilities', 'bitsum-parkcontrol-icon', 'TLP / cpupower (CLI) / CPU Power Manager (GNOME extension)', 0, '', NULL);
INSERT OR REPLACE INTO apps (id, name, description, category, icon, linux_alternative, popularity, homepage, alternative_to) VALUES ('bitsum-processlasso', 'Process Lasso', 'Process Lasso is a tool designed to manage and edit how your processes and services run. It offers a robust list of capabilities including default process priorities and affinities, termination of disallowed processes, instance count limits, a system responsiveness graph, logging of processes, keep select processes running (auto-restart), and much more.', 'Design', 'bitsum-processlasso-icon', 'Ananicy-cpp (Auto Nice daemon) / Systemd resource control / nice / renice', 0, 'https://bitsum.com', NULL);
