INSERT OR REPLACE INTO apps (id, name, description, category, icon, linux_alternative, popularity, homepage, alternative_to) VALUES ('bitnami-wamp', 'Bitnami WAMP Stack', 'Bitnami WAMP Stack provides a complete, fully-integrated and ready to run WAMP development environment. In addition to PHP, MySQL and Apache, it includes FastCGI, OpenSSL, phpMyAdmin, ModSecurity, SQLite, ImageMagick, xDebug, Xcache, OpenLDAP, ModSecurity, Memcache, OAuth, PEAR, PECL, APC, GD, cURL and other components and the following frameworks: Zend Framework, Symfony, CodeIgniter, CakePHP, Smarty, Laravel.', 'Development', 'bitnami-wamp-icon', 'LAMP Stack (Linux, Apache, MySQL, PHP) / Docker / XAMPP for Linux', 0, 'https://bitnami.com/stack/wamp', NULL);
