INSERT OR REPLACE INTO apps (id, name, description, category, icon, linux_alternative, popularity, homepage, alternative_to) VALUES ('brio-foldersize', 'Folder Size', 'Folder Size for Windows opens pop-up windows that track open Explorer windows. The new window shows not only the size of files, but also the size of folders. It keeps track of which folders you view, and scans them in the background so you can see complete size of all files within the folder. It''s very useful for cleaning up your disk. Once you get used to having that information available, a directory listing simply looks incomplete without it!', 'Utilities', 'brio-foldersize-icon', 'Baobab (Disk Usage Analyzer) / QDirStat / Ncdu', 0, 'http://foldersize.sourceforge.net/', NULL);
